static void cb_card(lv_event_t *e)
{
    int idx = (int)(intptr_t)lv_event_get_user_data(e);
    switch(idx) {
        case 0: on_menu_luces();   break;
        case 1: on_menu_spotify(); break;
        case 2:
            mm.porton_open = !mm.porton_open;
            if (mm.lbl_porton) {
                lv_label_set_text(mm.lbl_porton,
                    mm.porton_open ? LV_SYMBOL_OK " ABIERTO" : LV_SYMBOL_CLOSE " CERRADO");
                lv_obj_set_style_text_color(mm.lbl_porton,
                    mm.porton_open ? lv_color_hex(0x44FF99) : lv_color_hex(0xFF4444), 0);
            }
            on_menu_porton();
            break;
        case 3: on_menu_sonido();  break;
        case 4: on_menu_settings(); break;
    }
}

static void cb_refresh(lv_event_t *e) { (void)e; on_menu_refresh(); }

