static void node_anim_cb(lv_timer_t *t)
{
    (void)t;
    if (mm.paused) return;
    static int frame = 0; frame++;
    for (int i = 0; i < NODE_N; i++) {
        if (!mm.nodes[i]) continue;
        int bx = (i % 7) * 150 + 40;
        int by = (i / 7) * 110 + 60 + TOP_H;
        int ox = (int)(14.f * lv_trigo_sin((frame*3+i*47)%360) / 32767);
        int oy = (int)(9.f  * lv_trigo_sin((frame*2+i*73+90)%360) / 32767);
        lv_obj_set_pos(mm.nodes[i], bx+ox-3, by+oy-3);
    }
}

static void build_nodes(lv_obj_t *parent)
{
    for (int i = 0; i < NODE_N; i++) {
        lv_obj_t *n = lv_obj_create(parent);
        lv_obj_set_size(n, 6, 6);
        lv_obj_set_style_bg_color(n, lv_color_hex(0x7F77DD), 0);
        lv_obj_set_style_bg_opa(n, LV_OPA_50, 0);
        lv_obj_set_style_border_width(n, 0, 0);
        lv_obj_set_style_radius(n, 3, 0);
        lv_obj_set_style_shadow_width(n, 0, 0);
        lv_obj_clear_flag(n, LV_OBJ_FLAG_SCROLLABLE | LV_OBJ_FLAG_CLICKABLE);
        lv_obj_set_pos(n, (i%7)*150+40, (i/7)*110+60+TOP_H);
        mm.nodes[i] = n;
    }
    mm.anim_tmr = lv_timer_create(node_anim_cb, 60, NULL);
}

