static void build_topbar(lv_obj_t *parent)
{
    lv_obj_t *bar = lv_obj_create(parent);
    lv_obj_set_size(bar, SCR_W, TOP_H);
    lv_obj_set_pos(bar, 0, 0);
    lv_obj_add_style(bar, &s_top, 0);
    lv_obj_clear_flag(bar, LV_OBJ_FLAG_SCROLLABLE);

    /* WiFi chip */
    mm.lbl_wifi = lv_label_create(bar);
    lv_label_set_text(mm.lbl_wifi, LV_SYMBOL_WIFI " " LV_SYMBOL_CLOSE);
    lv_obj_set_style_text_font(mm.lbl_wifi, &lv_font_montserrat_18, 0);
    lv_obj_set_style_text_color(mm.lbl_wifi, lv_color_hex(0xFF4444), 0);
    lv_obj_align(mm.lbl_wifi, LV_ALIGN_LEFT_MID, 16, 0);

    /* Titulo */
    lv_obj_t *title = lv_label_create(bar);
    lv_label_set_text(title, "SM Soluciones Informaticas");
    lv_obj_set_style_text_font(title, &lv_font_montserrat_20, 0);
    lv_obj_set_style_text_color(title, C_TEXT, 0);
    lv_obj_align(title, LV_ALIGN_CENTER, 0, 0);

    /* HA chip */
    mm.lbl_ha = lv_label_create(bar);
    lv_label_set_text(mm.lbl_ha, "HA: Off-Line");
    lv_obj_set_style_text_font(mm.lbl_ha, &lv_font_montserrat_18, 0);
    lv_obj_set_style_text_color(mm.lbl_ha, lv_color_hex(0xFF4444), 0);
    lv_obj_align(mm.lbl_ha, LV_ALIGN_RIGHT_MID, -16, 0);

    /* Linea inferior */
    lv_obj_t *ln = lv_obj_create(parent);
    lv_obj_set_size(ln, SCR_W, 1);
    lv_obj_set_pos(ln, 0, TOP_H);
    lv_obj_add_style(ln, &s_line, 0);
}

