static void build_botbar(lv_obj_t *parent)
{
    int by = SCR_H - BOT_H;

    lv_obj_t *ln = lv_obj_create(parent);
    lv_obj_set_size(ln, SCR_W, 1);
    lv_obj_set_pos(ln, 0, by - 1);
    lv_obj_add_style(ln, &s_line, 0);

    lv_obj_t *bar = lv_obj_create(parent);
    lv_obj_set_size(bar, SCR_W, BOT_H);
    lv_obj_set_pos(bar, 0, by);
    lv_obj_add_style(bar, &s_bot, 0);
    lv_obj_clear_flag(bar, LV_OBJ_FLAG_SCROLLABLE);

    /* Boton refresh */
    lv_obj_t *btn = lv_btn_create(bar);
    lv_obj_set_size(btn, 28, 28);
    lv_obj_align(btn, LV_ALIGN_LEFT_MID, 10, 0);
    lv_obj_set_style_bg_color(btn, lv_color_hex(0x111122), 0);
    lv_obj_set_style_border_color(btn, lv_color_hex(0x2A2A5A), 0);
    lv_obj_set_style_border_width(btn, 1, 0);
    lv_obj_set_style_radius(btn, 7, 0);
    lv_obj_set_style_shadow_width(btn, 0, 0);
    lv_obj_add_event_cb(btn, cb_refresh, LV_EVENT_CLICKED, NULL);
    lv_obj_t *ric = lv_label_create(btn);
    lv_label_set_text(ric, LV_SYMBOL_REFRESH);
    lv_obj_set_style_text_color(ric, lv_color_hex(0x7070CC), 0);
    lv_obj_center(ric);

    /* Fecha */
    mm.lbl_date = lv_label_create(bar);
    lv_label_set_text(mm.lbl_date, "-");
    lv_obj_set_style_text_font(mm.lbl_date, &lv_font_montserrat_18, 0);
    lv_obj_set_style_text_color(mm.lbl_date, lv_color_hex(0x8080BB), 0);
    lv_obj_align(mm.lbl_date, LV_ALIGN_LEFT_MID, 50, 0);

    /* Hora */
    mm.lbl_time = lv_label_create(bar);
    lv_label_set_text(mm.lbl_time, "--:--:--");
    lv_obj_set_style_text_font(mm.lbl_time, &lv_font_montserrat_20, 0);
    lv_obj_set_style_text_color(mm.lbl_time, lv_color_hex(0xA09AFF), 0);
    lv_obj_align(mm.lbl_time, LV_ALIGN_RIGHT_MID, -16, 0);
}

