static void build_card(lv_obj_t *parent, int idx)
{
    const card_t *c = &CARDS[idx];
    int col = CPOS[idx][0], row = CPOS[idx][1];
    int cx = PAD + col * (CARD_W + GAP);
    int cy = TOP_H + 1 + PAD + row * (CARD_H + GAP);

    lv_obj_t *card = lv_obj_create(parent);
    lv_obj_set_size(card, CARD_W, CARD_H);
    lv_obj_set_pos(card, cx, cy);
    lv_obj_add_style(card, &s_card, 0);
    lv_obj_add_style(card, &s_card_pr, LV_STATE_PRESSED);
    lv_obj_set_style_bg_color(card, lv_color_hex(c->cbg), 0);
    lv_obj_set_style_border_color(card, lv_color_hex(c->cborder), 0);
    /* pressed: slightly lighter */
    lv_obj_set_style_bg_color(card, lv_color_hex(c->cbg | 0x101020), LV_STATE_PRESSED);
    lv_obj_add_flag(card, LV_OBJ_FLAG_CLICKABLE);
    lv_obj_clear_flag(card, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_add_event_cb(card, cb_card, LV_EVENT_CLICKED, (void*)(intptr_t)idx);

    /* Icono centrado arriba */
    lv_obj_t *icon = lv_label_create(card);
    lv_label_set_text(icon, c->icon);
    lv_obj_set_style_text_font(icon, &lv_font_montserrat_48, 0);
    lv_obj_set_style_text_color(icon, lv_color_hex(c->cicon), 0);
    lv_obj_align(icon, LV_ALIGN_TOP_MID, 0, CARD_H/5);

    /* Nombre */
    lv_obj_t *name = lv_label_create(card);
    lv_label_set_text(name, c->name);
    lv_obj_set_style_text_font(name, &lv_font_montserrat_20, 0);
    lv_obj_set_style_text_color(name, lv_color_hex(c->clabel), 0);
    lv_obj_align(name, LV_ALIGN_TOP_MID, 0, CARD_H/5 + 58);

    /* Sub */
    lv_obj_t *sub = lv_label_create(card);
    lv_label_set_text(sub, c->sub);
    lv_obj_set_style_text_font(sub, &lv_font_montserrat_16, 0);
    lv_obj_set_style_text_color(sub, lv_color_hex(c->csub), 0);
    lv_obj_align(sub, LV_ALIGN_TOP_MID, 0, CARD_H/5 + 82);

    /* Estado Porton */
    if (idx == 2) {
        mm.lbl_porton = lv_label_create(card);
        lv_label_set_text(mm.lbl_porton, LV_SYMBOL_CLOSE " CERRADO");
        lv_obj_set_style_text_font(mm.lbl_porton, &lv_font_montserrat_16, 0);
        lv_obj_set_style_text_color(mm.lbl_porton, lv_color_hex(0xFF4444), 0);
        lv_obj_align(mm.lbl_porton, LV_ALIGN_TOP_MID, 0, CARD_H/5 + 108);
    }
}

