void main_menu_create(lv_obj_t *parent)
{
    ESP_LOGI(TAG, "Creando menu principal");
    memset(&mm, 0, sizeof(mm));
    init_styles();
    lv_obj_add_style(parent, &s_scr, 0);
    lv_obj_clear_flag(parent, LV_OBJ_FLAG_SCROLLABLE);

    build_nodes(parent);
    build_topbar(parent);
    build_botbar(parent);
    for (int i = 0; i < 5; i++) build_card(parent, i);

    ESP_LOGI(TAG, "Menu principal creado");
}

void main_menu_tick(void) {}

void main_menu_set_wifi(bool connected)
{
    if (!mm.lbl_wifi) return;
    lv_label_set_text(mm.lbl_wifi, connected ? LV_SYMBOL_WIFI " WiFi" : LV_SYMBOL_WIFI " " LV_SYMBOL_CLOSE);
    lv_obj_set_style_bg_color(lv_obj_get_parent(mm.lbl_wifi), connected ? lv_color_hex(0x1A3A1A) : lv_color_hex(0x5A0A0A), 0);
    lv_obj_set_style_text_color(mm.lbl_wifi, connected ? lv_color_hex(0x44FF88) : lv_color_hex(0xFF4444), 0);




}

void main_menu_set_ha(bool online)
{
    if (!mm.lbl_ha) return;
    lv_label_set_text(mm.lbl_ha, online ? "HA: Online " LV_SYMBOL_OK : "HA: Off-Line");
    lv_obj_set_style_bg_color(lv_obj_get_parent(mm.lbl_ha), online ? lv_color_hex(0x1A3A1A) : lv_color_hex(0x5A0A0A), 0);
    lv_obj_set_style_text_color(mm.lbl_ha, online ? lv_color_hex(0x44FF88) : lv_color_hex(0xFF4444), 0);
}





void main_menu_set_datetime(const char *date, const char *time)
{
    if (mm.lbl_date && date) lv_label_set_text(mm.lbl_date, date);
    if (mm.lbl_time && time) lv_label_set_text(mm.lbl_time, time);
}

void main_menu_pause(void)  { mm.paused = true;  }
void main_menu_resume(void) { mm.paused = false; }
